head.b:skin:
:root{
  --brand-teal:#1f8a82;
  --brand-teal-dark:#146560;
  --brand-teal-light:#e7f4f3;
  --brand-orange:#f4753d;
  --brand-orange-dark:#d9581e;
  --brand-dark:#16191c;
}
*{box-sizing:border-box;}
body{
  margin:0;
  font-family:'Montserrat',sans-serif;
  color:var(--brand-dark);
  background:#ffffff;
  -webkit-font-smoothing:antialiased;
}
a{color:inherit;text-decoration:none;}
img{max-width:100%;display:block;}
.container{max-width:1200px;margin:0 auto;padding:0 24px;}

/* Header */
.site-header{
  background:#ffffff;
  border-bottom:1px solid rgba(22,25,28,0.08);
  position:sticky;top:0;z-index:50;
}
.site-header-inner{
  display:flex;align-items:center;justify-content:space-between;
  gap:24px;padding:18px 0;
}
.site-logo{
  font-size:28px;font-weight:900;font-style:italic;color:var(--brand-dark);
  flex-shrink:0;
}
.site-logo .dot{color:var(--brand-orange);}
.site-nav{display:flex;align-items:center;gap:28px;flex-wrap:wrap;font-weight:600;font-size:14px;}
.site-nav a{transition:color .2s;}
.site-nav a:hover, .site-nav a.is-active{color:var(--brand-orange);}
.site-nav a.is-active{border-bottom:2px solid var(--brand-orange);padding-bottom:4px;}
.donate-pill{
  background:var(--brand-orange);color:#fff !important;padding:10px 24px;
  border-radius:999px;font-weight:700;font-size:14px;white-space:nowrap;
  transition:background .2s;
}
.donate-pill:hover{background:var(--brand-orange-dark);}
.nav-toggle{display:none;background:none;border:0;font-size:26px;cursor:pointer;color:var(--brand-dark);}

/* Page banner */
.page-banner{
  background:var(--brand-dark);color:#fff;text-align:center;
  padding:64px 24px;
}
.page-banner p{margin:0 0 10px;color:var(--brand-orange);font-weight:700;font-size:13px;letter-spacing:.08em;text-transform:uppercase;}
.page-banner h1{margin:0;font-size:40px;font-weight:800;line-height:1.15;}

/* Layout */
.content-wrap{
  display:grid;grid-template-columns:2fr 1fr;gap:48px;
  padding:56px 0;align-items:start;
}

/* Post cards */
.blog-posts{display:flex;flex-direction:column;gap:40px;}
.post-card{
  border:1px solid rgba(22,25,28,0.08);border-radius:20px;overflow:hidden;
  transition:box-shadow .2s, transform .2s;background:#fff;
}
.post-card:hover{box-shadow:0 12px 30px rgba(22,25,28,0.08);transform:translateY(-2px);}
.post-thumb{width:100%;height:280px;object-fit:cover;}
.post-body-inner{padding:28px;}
.post-date{margin:0 0 10px;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:.06em;color:var(--brand-teal);}
.post-title{margin:0 0 12px;font-size:26px;font-weight:800;line-height:1.25;}
.post-title a:hover{color:var(--brand-orange);}
.post-snippet{margin:0 0 16px;font-size:15px;line-height:1.7;color:#5b6169;}
.post-meta-row{display:flex;align-items:center;justify-content:space-between;margin-top:4px;}
.post-readmore{font-weight:700;font-size:14px;color:var(--brand-orange);}
.post-readmore:hover{color:var(--brand-teal);}
.post-comments-link{font-size:13px;font-weight:600;color:#8a8f96;}

.blog-pager{display:flex;justify-content:space-between;margin-top:16px;font-weight:700;font-size:14px;}
.blog-pager a{color:var(--brand-teal);}
.blog-pager a:hover{color:var(--brand-orange);}

/* Single post */
.post-full .post-title{font-size:34px;}
.post-full .post-thumb{height:auto;border-radius:16px;margin-bottom:24px;}
.post-full .post-body-inner{padding:0;}
.post-full-content{font-size:16px;line-height:1.85;color:#33373c;}
.post-full-content img{border-radius:12px;margin:20px 0;}
.post-labels{margin-top:28px;display:flex;flex-wrap:wrap;gap:8px;}
.post-labels a{
  background:var(--brand-teal-light);color:var(--brand-teal-dark);
  font-size:12px;font-weight:700;padding:6px 14px;border-radius:999px;
}

/* Sidebar */
.sidebar-widget{
  background:#fafafa;border-radius:20px;padding:28px;margin-bottom:28px;
  border:1px solid rgba(22,25,28,0.06);
}
.sidebar-widget h2{margin:0 0 18px;font-size:16px;font-weight:800;text-transform:uppercase;letter-spacing:.04em;color:var(--brand-dark);}
.about-card{background:var(--brand-dark);color:#fff;}
.about-card h2{color:#fff;}
.about-card p{font-size:14px;line-height:1.7;color:rgba(255,255,255,0.75);margin:0 0 18px;}
.about-card .donate-pill{display:inline-block;}
.search-widget input{
  width:100%;padding:12px 16px;border-radius:999px;border:1px solid #d8dade;
  font-family:inherit;font-size:14px;outline:none;
}
.search-widget input:focus{border-color:var(--brand-orange);}
.label-list{list-style:none;margin:0;padding:0;}
.label-list li{border-bottom:1px solid rgba(22,25,28,0.06);}
.label-list li:last-child{border-bottom:0;}
.label-list a{
  display:flex;justify-content:space-between;padding:10px 0;font-size:14px;font-weight:600;
}
.label-list a:hover{color:var(--brand-orange);}

/* Footer */
.site-footer{background:var(--brand-dark);color:rgba(255,255,255,0.7);padding:56px 0 24px;margin-top:40px;}
.footer-top{display:grid;grid-template-columns:1.6fr 1fr 1fr;gap:40px;padding-bottom:40px;border-bottom:1px solid rgba(255,255,255,0.1);}
.footer-logo{font-size:26px;font-weight:900;font-style:italic;color:#fff;margin-bottom:14px;}
.footer-logo .dot{color:var(--brand-orange);}
.footer-tagline{font-size:13px;line-height:1.7;max-width:280px;}
.footer-col h4{color:#fff;font-size:14px;font-weight:700;margin:0 0 16px;}
.footer-col ul{list-style:none;margin:0;padding:0;display:flex;flex-direction:column;gap:10px;}
.footer-col a{font-size:13px;transition:color .2s;}
.footer-col a:hover{color:var(--brand-orange);}
.footer-bottom{
  display:flex;justify-content:space-between;flex-wrap:wrap;gap:12px;
  padding-top:22px;font-size:12px;color:rgba(255,255,255,0.5);
}
.footer-bottom a{color:rgba(255,255,255,0.5);}
.attribution{font-size:11px;color:rgba(255,255,255,0.35);margin-top:8px;}

@media (max-width:900px){
  .content-wrap{grid-template-columns:1fr;}
  .footer-top{grid-template-columns:1fr;}
  .site-nav{
    display:none;position:absolute;top:100%;left:0;right:0;background:#fff;
    flex-direction:column;align-items:flex-start;gap:0;
    border-top:1px solid rgba(22,25,28,0.08);box-shadow:0 12px 20px rgba(0,0,0,0.06);
  }
  .site-nav.is-open{display:flex;}
  .site-nav a{width:100%;padding:14px 24px;border-bottom:1px solid rgba(22,25,28,0.06);}
  .site-nav .donate-pill{margin:14px 24px;}
  .nav-toggle{display:block;}
  .site-header-inner{position:relative;}
}
@media (max-width:520px){
  .page-banner h1{font-size:30px;}
  .post-thumb{height:200px;}
}
